/*selectBaddcoList*/ SELECT CONCAT(ADDCOKY) AS ROWKEY , ADDCOKY, ADDSIKY , MINLENG, MAXLENG, MINWIDT, MAXWIDT , ADCOPER,DATE_FORMAT(CREDATE,'%Y-%m-%d') as CREDATE, DATE_FORMAT(STR_TO_DATE(CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${schema}.FN_SY_USERNAM(CREUSER) AS CREUSER , DATE_FORMAT(LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(LMOTIME,'%H%i%s'),'%H:%i:%s') as LMOTIME , ${schema}.FN_SY_USERNAM(LMOUSER) AS LMOUSER , UPDTCHK FROM ${schema}.BADDCO
AND ADDSIKY LIKE CONCAT('%', #{param.addsiky}, '%')
AND SYSCDYN = #{param.syscdyn}
AND SYSCDYN = 'N'
ORDER BY ADDCOKY ASC

mapper.delete:
