/*selectBtrfmaList*/ SELECT CONCAT(BT.WAREKEY, BT.BTRFKEY) AS ROWKEY , BT.WAREKEY, MW.WHNAMLC, BT.BTRFKEY, BT.STNWEIG , BT.BTRCATE, BT.BTRFITC, BT.BTRFITN, BT.BTRFIGB , BT.BTRFICT, BT.BTRFITM, BT.BTRFCHR, BT.BTRFPAY , BT.BTRFSTC, BT.BTRFEYN, BT.SIZGBYN, BT.BTRDFYN , DATE_FORMAT(STR_TO_DATE(CONCAT(LEFT(BT.BTRFDAF, 4), '-', RIGHT(BT.BTRFDAF, 2)), '%Y-%m'), '%Y-%m') AS BTRFDAF , DATE_FORMAT(STR_TO_DATE(CONCAT(LEFT(BT.BTRFDAT, 4), '-', RIGHT(BT.BTRFDAT, 2)), '%Y-%m'), '%Y-%m') AS BTRFDAT , DATE_FORMAT(BT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(BT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userInfo.schema}.FN_SY_USERNAM(BT.CREUSER) AS CREUSER , DATE_FORMAT(BT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(BT.LMOTIME,'%H%i%s'),'%H:%i:%s') as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(BT.LMOUSER) AS LMOUSER , BT.UPDTCHK FROM ${userInfo.schema}.BTRFMA BT INNER JOIN ${userInfo.schema}.MWARMA MW ON BT.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y'
AND BT.WAREKEY = #{param.warekey}
AND BT.BTRCATE = #{param.btrcate}
AND REPLACE(#{param.btrfdaf}, '-', '') BETWEEN BT.BTRFDAF AND BT.BTRFDAT
AND (REPLACE(#{param.btrfdaf}, '-', '') BETWEEN BT.BTRFDAF AND BT.BTRFDAT OR REPLACE(#{param.btrfdat}, '-', '') BETWEEN BT.BTRFDAF AND BT.BTRFDAT)
AND BT.BTRFITC = #{param.btrfitc}
AND BT.BTRFIGB = #{param.btrfigb}
AND BT.BTRFITM = #{param.btrfitm}
ORDER BY BT.WAREKEY, BT.BTRCATE, BT.BTRFITC, BT.BTRFITN, BT.BTRFIGB, BT.BTRFICT, BT.BTRFKEY

/*selectBsizpaList*/ SELECT CONCAT(BS.WAREKEY, BS.BTRNKEY, BS.ADDSIKY) AS ROWKEY , BS.WAREKEY, BS.BTRNKEY, BS.ADDSIKY , BS.DOCCATE, BS.DOCTYPE, BS.BSIZPAY, MW.WHNAMLC , MC.COMCDTX, DATE_FORMAT(BS.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(BS.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME, BS.CREUSER , DATE_FORMAT(BS.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(BS.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME, BS.LMOUSER , BS.UPDTCHK FROM ${schema}.BSIZPA BS INNER JOIN ${schema}.BTRFMA BF ON BS.WAREKEY = BF.WAREKEY AND BS.BTRNKEY = BF.BTRFKEY INNER JOIN ${schema}.MCODEM MC ON MC.COMCDKY = 'ADDSIKY' AND BS.ADDSIKY = MC.COMCDVL AND MC.COUSEYN = 'Y' INNER JOIN ${schema}.MWARMA MW ON MW.WAREKEY = BS.WAREKEY AND MW.WHUSEYN = 'Y'
AND BS.BTRNKEY = #{param.btrnkey}
AND BS.DOCTYPE = #{param.doctype}
ORDER BY MC.COMCDOR

