mapper.select:
/*selectBtrpmaList*/
	SELECT
		CONCAT(BP.WAREKEY, BP.BTRPKEY) AS ROWKEY,
		BP.WAREKEY, MW.WHNAMLC, BP.BTRPKEY, BP.STNWEIG,
		BP.BTRCATE, BP.REGIKEY, MR.RENAMLC, BP.BTRPITC,
		BP.BTRPITN, BP.BTRPIGB, BP.BTRPICT, BP.BTRPVAF,
		BP.BTRPITM, BP.BTRPCHR, BP.BTRPPAY, BP.BTRPEYN,
		BP.BTRDFYN, BP.SIZGBYN, BP.BTRDFYN,
		DATE_FORMAT(STR_TO_DATE(CONCAT(LEFT(BP.BTRPDAF, 4), '-', RIGHT(BP.BTRPDAF, 2)), '%Y-%m'), '%Y-%m') AS BTRPDAF,
	    DATE_FORMAT(STR_TO_DATE(CONCAT(LEFT(BP.BTRPDAT, 4), '-', RIGHT(BP.BTRPDAT, 2)), '%Y-%m'), '%Y-%m') AS BTRPDAT,
		DATE_FORMAT(BP.CREDATE,'%Y-%m-%d') as CREDATE,
	    DATE_FORMAT(STR_TO_DATE(BP.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME,
	    ${userInfo.schema}.FN_SY_USERNAM(BP.CREUSER) AS CREUSER,
	    DATE_FORMAT(BP.LMODATE,'%Y-%m-%d') as LMODATE ,
	    DATE_FORMAT(STR_TO_DATE(BP.LMOTIME,'%H%i%s'),'%H:%i:%s') as LMOTIME,
		${userInfo.schema}.FN_SY_USERNAM(BP.LMOUSER) AS LMOUSER,
		BP.UPDTCHK
	FROM ${userInfo.schema}.BTRPMA BP
	INNER JOIN ${userInfo.schema}.MWARMA MW
		ON MW.WAREKEY = BP.WAREKEY
		AND MW.WHUSEYN ='Y'
	INNER JOIN ${userInfo.schema}.MREGMA MR
		ON MR.REGIKEY = BP.REGIKEY
		AND MR.REUSEYN ='Y'


			AND BP.BTRPKEY = #{param.btrpkey}


			AND BP.WAREKEY = #{param.warekey}


			AND BP.BTRCATE = #{param.btrcate}


			AND BP.BTRPITC = #{param.btrpitc}


			AND BP.BTRPIGB = #{param.btrpigb}


			AND BP.STNWEIG = #{param.stnweig}



				AND MR.REGIKEY IN

					#{item}



				AND MR.REGIKEY = #{param.regikey}



			AND BP.BTRPVAF = #{param.btrpvaf}


			AND BP.SIZGBYN = #{param.sizgbyn}


	 		AND REPLACE(#{param.btrpdaf}, '-', '') BETWEEN BP.BTRPDAF AND BP.BTRPDAT


	 		AND (REPLACE(#{param.btrpdaf}, '-', '') BETWEEN BP.BTRPDAF AND BP.BTRPDAT
	 		 OR REPLACE(#{param.btrpdat}, '-', '') BETWEEN BP.BTRPDAF AND BP.BTRPDAT)


	 		AND BP.BTRDFYN = #{param.btrdfyn}


	 		AND BP.BTRPEYN = #{param.btrpeyn}


	  ORDER BY BP.WAREKEY, BP.REGIKEY, BP.BTRCATE, BP.BTRPITC, BP.BTRPITN, BP.BTRPIGB, BP.BTRPICT, BP.BTRPVAF, BP.BTRPKEY

