mapper.sql:
SELECT CONCAT(WI.RCVDCKY,WI.RCVDCKY) AS ROWKEY , WI.RCVDCKY, DATE_FORMAT(WI.POSHPDT, '%Y-%m-%d') AS POSHPDT , DATE_FORMAT(STR_TO_DATE(WI.POSHPTM,'%H%i%s'),'%H:%i:%s') AS POSHPTM , WI.BTRFSTC, WI.BTRCATE, BC.BTRCNAM, WI.POSHPDY , DATE_FORMAT(WI.RCVDCDT, '%Y-%m-%d') AS RCVDCDT , DATE_FORMAT(STR_TO_DATE(WI.RCVDCTM, '%H%i%s'), '%H:%i:%s') AS RCVDCTM , WI.WAREKEY, WH.DOCCATE, WH.DOCTYPE, MD.DOCCTNM , MD.DOCTYNM, WI.RCVDCIT, WI.SKUMKEY, WI.SKUDESC , WI.INVOICE, WI.ITEMCOD AS BTRFITC, MC.COMCDTX AS BTRFITN, MC.CDCATE1 AS BTRFIGB , MC.CDATTR1 AS BTRFICT, WI.ADDCOKY, BA.ADDSIKY, WI.RCVITST , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = IFNULL(TS.BTRFITM, #{param.transfer})) AS BTRFIT1 , TS.BTRFITM AS #{param.transfer} , TS.BTRFKEY AS BTRFKY1 , TS.BTRFCHR AS BTRFCH1 , ( CASE WHEN (COALESCE(SC.STNWEIG, '') = #{param.stnweig} OR SC.STNWEIG IS NULL) AND TS.STNWEIG = #{param.stnweig} AND LD.STNWEIG = #{param.stnweig} THEN #{param.grossWgName} ELSE #{param.skuWeigName} END ) AS CALWEIG , COALESCE( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE TS.BTRFPAY END , 0) AS BTRFPA1 , COALESCE(( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE TS.BTRFPAY END ) * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) , 0) AS BTRFPC1_CAL , ( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE TS.BTRFPAY END ) * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) * (BA.ADCOPER) AS BTRFEP1_CAL , COALESCE( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN (TS.BTRFCHR * WI.GROSSWG) ELSE (TS.BTRFCHR * WI.SKUWEIG) END , 0) AS BTRFCC1_CAL , COALESCE( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN (TS.BTRFCHR * WI.GROSSWG * BA.ADCOPER) ELSE (TS.BTRFCHR * WI.SKUWEIG * BA.ADCOPER) END , 0) AS BTRFEC1_CAL , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = IFNULL(LD.BTRFITM, #{param.loading})) AS BTRFIT2 , IFNULL(LD.BTRFITM, #{param.loading}) AS #{param.loading} , LD.BTRFKEY AS BTRFKY2 , LD.BTRFCHR AS BTRFCH2 , COALESCE( CASE WHEN LD.STNWEIG = #{param.stnweig} THEN (LD.BTRFCHR * WI.GROSSWG) ELSE (LD.BTRFCHR * WI.SKUWEIG) END , 0) AS BTRFCC2_CAL , COALESCE( CASE WHEN LD.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = LD.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE LD.BTRFPAY END , 0 ) AS BTRFPA2 , COALESCE( CASE WHEN LD.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = LD.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE LD.BTRFPAY END , 0) * ( CASE WHEN LD.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) AS BTRFPC2_CAL , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = IFNULL(SC.BTRFITM, #{param.selection})) AS BTRFIT3 , IFNULL(SC.BTRFITM, #{param.selection}) AS #{param.selection} , SC.BTRFKEY AS BTRFKY3 , SC.BTRFCHR AS BTRFCH3 , COALESCE( CASE WHEN SC.STNWEIG = #{param.stnweig} THEN (SC.BTRFCHR * WI.GROSSWG) ELSE (SC.BTRFCHR * WI.SKUWEIG) END , 0) AS BTRFCC3_CAL , COALESCE( CASE WHEN SC.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = SC.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE SC.BTRFPAY END , 0) AS BTRFPA3 , COALESCE( ( CASE WHEN SC.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = SC.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE SC.BTRFPAY END ) * ( CASE WHEN SC.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) , 0) AS BTRFPC3_CAL , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = IFNULL(ST.BTRFITM, #{param.storage})) AS BTRFIT4 , IFNULL(ST.BTRFITM, #{param.storage}) AS #{param.storage} , ST.BTRFKEY AS BTRFKY4 , ST.BTRFCHR AS BTRFCH4 , COALESCE( CASE WHEN ST.STNWEIG = #{param.stnweig} THEN (ST.BTRFCHR * WI.GROSSWG) ELSE (ST.BTRFCHR * WI.SKUWEIG) END , 0) AS BTRFCC4_CAL , COALESCE( CASE WHEN ST.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = ST.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE ST.BTRFPAY END , 0) AS BTRFPA4 , COALESCE( ( CASE WHEN ST.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = ST.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE ST.BTRFPAY END ) * ( CASE WHEN ST.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) , 0) AS BTRFPC4_CAL , ( CASE WHEN WEEKDAY(WI.POSHPDT) IN (5,6) OR ( TIME(WI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(WA.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(WI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(WA.HOLTMTO, '%H%i%s'), '%H%i%s') ) THEN TS.BTRFCHR * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) * (WA.HOLRATE / 100) ELSE 0 END ) AS HOLICHR , ( CASE WHEN WEEKDAY(WI.POSHPDT) IN (5,6) OR ( TIME(WI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(WA.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(WI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(WA.HOLTMTO, '%H%i%s'), '%H%i%s') ) THEN ( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE TS.BTRFPAY END ) * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) * (WA.HOLRATE / 100) ELSE 0 END ) AS HOLIPAY
, IFNULL( (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = BC.BTRFBTP), CASE WHEN TRIM(WI.OWNERKY) != '' OR WI.OWNERKY IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = WI.OWNERKY) WHEN TRIM(WI.OWNRNAM) != '' AND WI.OWNRNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = WI.OWNRNAM LIMIT 1) WHEN TRIM(WI.CUSTNAM) != '' AND WI.CUSTNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = WI.CUSTNAM LIMIT 1) ELSE '' END ) AS BTRFCBT
, ( CASE WHEN TRIM(WI.OWNERKY) != '' OR WI.OWNERKY IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = WI.OWNERKY AND SURCHYN ='Y') WHEN TRIM(WI.OWNRNAM) != '' AND WI.OWNRNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = WI.OWNRNAM AND SURCHYN ='Y' LIMIT 1) WHEN TRIM(WI.CUSTNAM) != '' AND WI.CUSTNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = WI.CUSTNAM AND SURCHYN ='Y' LIMIT 1) ELSE '' END ) AS SBILLTO , BA.ADCOPER, WI.GROSSWD, WI.SKUWIDT, WI.SKULENG , WI.SKUWEIG, WI.GROSSWG, WI.REGIORG, WI.REGIMOD , WI.GROSSLN, WI.SKUTHIC, WI.INBDATE, WI.INBVHNM , WI.OWNERKY, WI.OWNRNAM, WI.CUSTCOD, WI.CUSTNAM , WI.DEORGNM, WI.DEMODNM, WI.DEMDMAN, WI.DEMDADR , WI.DEMPOCD, WI.DEMDTLN , WH.VOWNKEY AS BTRFPAT , WH.VEHICKY , MV.VONAMLC , (SELECT CDATTR1 FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'VHCTNCD' AND COMCDVL = VH.VHCTNCD) AS TRFDFSD , VH.VHCFNAM, MR.RENAMLC AS REORGNM , RM.RENAMLC AS REMODNM, WI.EOASNKY, WI.EOASNIT , DATE_FORMAT(WI.CREDATE, '%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(WI.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME , ${userInfo.schema}.FN_SY_USERNAM(WI.CREUSER) AS CREUSER , DATE_FORMAT(WI.LMODATE, '%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(WI.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(WI.LMOUSER) AS LMOUSER , WI.UPDTCHK FROM ${userInfo.schema}.WRCVIT WI INNER JOIN ${userInfo.schema}.WRCVHD WH ON WH.WAREKEY = WI.WAREKEY AND WH.RCVDCKY = WI.RCVDCKY AND WH.DOCCATE = '400' AND WH.DOCTYPE != '490' INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = WI.BTRCATE AND BC.TFONLYN = 'N' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = WH.WAREKEY AND MD.DOCCATE = WH.DOCCATE AND MD.DOCTYPE = WH.DOCTYPE INNER JOIN ${userInfo.schema}.MCODEM MC ON MC.COMCDKY = 'ITEMCOD' AND MC.COMCDVL = WI.ITEMCOD AND MC.COUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MWARMA WA ON WA.WAREKEY = WI.WAREKEY INNER JOIN ${userInfo.schema}.BADDCO BA ON BA.ADDCOKY = WI.ADDCOKY LEFT JOIN BTRF TS ON TS.WAREKEY = WI.WAREKEY AND TS.BTRCATE = WI.BTRCATE AND TS.BTRFITC = WI.ITEMCOD AND TS.BTRFITM = #{param.transfer} AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN TS.BTRFDAF AND TS.BTRFDAT) LEFT JOIN BTRF LD ON LD.WAREKEY = WI.WAREKEY AND LD.BTRCATE = WI.BTRCATE AND LD.BTRFITC = WI.ITEMCOD AND LD.BTRFITM = #{param.loading} AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN LD.BTRFDAF AND LD.BTRFDAT) LEFT JOIN BTRF SC ON SC.WAREKEY = WI.WAREKEY AND SC.BTRCATE = WI.BTRCATE AND SC.BTRFITC = WI.ITEMCOD AND SC.BTRFITM = #{param.selection} AND (SC.BTRFSTC = WI.BTRFSTC OR TRIM(SC.BTRFSTC) = '') AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN SC.BTRFDAF AND SC.BTRFDAT) LEFT JOIN BTRF ST ON ST.WAREKEY = WI.WAREKEY AND ST.BTRCATE = WI.BTRCATE AND ST.BTRFITC = WI.ITEMCOD AND ST.BTRFITM = #{param.storage} AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN ST.BTRFDAF AND ST.BTRFDAT) INNER JOIN ${userInfo.commonSchema}.MVOWMA MV ON MV.VOWNKEY = WH.VOWNKEY AND MV.VOUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA VH ON VH.VOWNKEY = WH.VOWNKEY AND VH.VEHICKY = WH.VEHICKY AND VH.VHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MREGMA MR ON MR.REGIKEY = WI.REGIORG AND MR.REUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MREGMA RM ON RM.REGIKEY = WI.REGIMOD AND RM.REUSEYN = 'Y' WHERE WH.ICLOSYN = 'N' AND WH.RCVDCST = 'RVCMP' AND WI.RCVITST IN ('RVCOMP','RETURN')
AND WI.WAREKEY = #{param.warekey}
AND VH.VHCFNAM LIKE CONCAT ('%',#{param.vhcfnam},'%')
AND BA.ADDSIKY = #{param.addsiky}
AND WI.POSHPDT >= #{param.poshpdtfrom}
AND WI.POSHPDT <= #{param.poshpdtto}
AND WI.POSHPDT BETWEEN #{param.poshpdtfrom} AND #{param.poshpdtto}

mapper.select:
/* selectDoe082List */ WITH BTRF AS (
), CALCULATED_VALUES AS (
) SELECT FLOOR(CV.BTRFCC1_CAL / 1000) AS BTRFCC1 , FLOOR(CV.BTRFPC1_CAL / 1000) AS BTRFPC1 , FLOOR(CV.BTRFEC1_CAL / 1000) AS BTRFEC1 , FLOOR(CV.BTRFEP1_CAL / 1000) AS BTRFEP1 , FLOOR(CV.BTRFCC2_CAL / 1000) AS BTRFCC2 , FLOOR(CV.BTRFPC2_CAL / 1000) AS BTRFPC2 , FLOOR(CV.BTRFCC3_CAL / 1000) AS BTRFCC3 , FLOOR(CV.BTRFPC3_CAL / 1000) AS BTRFPC3 , FLOOR(CV.BTRFCC4_CAL / 1000) AS BTRFCC4 , FLOOR(CV.BTRFPC4_CAL / 1000) AS BTRFPC4 , FLOOR(CV.HOLICHR / 1000) AS HOLICHR , FLOOR(CV.HOLIPAY / 1000) AS HOLIPAY , FLOOR((CV.BTRFCC1_CAL + CV.BTRFEC1_CAL + CV.BTRFCC2_CAL + CV.BTRFCC3_CAL + CV.BTRFCC4_CAL + CV.HOLICHR) / 1000) AS TOTITCH , FLOOR((CV.BTRFPC1_CAL + CV.BTRFEP1_CAL + CV.BTRFPC2_CAL + CV.BTRFPC3_CAL + CV.BTRFPC4_CAL + CV.HOLIPAY) / 1000) AS TOTITPA , IF(CV.BTRFCBT != '',(SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = CV.BTRFCBT), '') AS BTRFBTP , IF(CV.SBILLTO != '',(SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = CV.SBILLTO AND SURCHYN = 'Y'), '') AS SBILLNM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'RCVITST' AND COMCDVL = CV.RCVITST) AS RCVITST , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = CV.ADDSIKY) AS ADCONAM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'STNWEIG' AND CDATTR1 = CV.CALWEIG) AS CALWGNM , CV.* FROM CALCULATED_VALUES CV ORDER BY CV.POSHPDT, CV.RCVDCKY, CV.RCVDCIT

mapper.update:
/* updateWrcvitCloseyn */
	UPDATE ${userInfo.schema}.WRCVHD

		 ICLOSYN = #{param.iclosyn}
		, ICLODAT = TO_CHAR(CURRENT_TIMESTAMP(), "YYYYMMDD")
	    , ICLOTIM = TO_CHAR(CURRENT_TIMESTAMP(), "HH24MISS")
	    , ICLOUSR = #{userInfo.useract}
	    , ICLOHKY = #{param.bfhdkey}
		, UPDTCHK = UPDTCHK + 1


		RCVDCKY = #{param.rcvdcky}
	AND WAREKEY = #{param.warekey}
	AND UPDTCHK = (SELECT UPDTCHK FROM ${userInfo.schema}.WRCVHD WHERE WAREKEY = #{param.warekey} AND RCVDCKY = #{param.rcvdcky})

mapper.select:
/* selectBtrfhdList */ SELECT BH.BFHDKEY AS ROWKEY , BH.DFSTDCH, BH.DFSTDPA , BH.WAREKEY, BH.BFHDKEY, BH.VOWNKEY, BH.VEHICKY , BH.TRFDFSD, BH.TRFDFWG, BH.TRFDFCH, BH.TRFDFPA , BH.TOORGCH, BH.TOSURCH, BH.TOTCHCO, BH.TOORGPA , BH.TOSURPA, BH.TOTPACO, MW.WHNAMLC, MV.VHCFNAM , BH.BFHMEMO, BI.TOTALWG, MW.HOLRATE , IF(BI.HOLICHR > 0 OR BI.HOLIPAY > 0, 'Y', 'N') AS HOLIDYN , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT1) AS BTRFIT1 , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT2) AS BTRFIT2 , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT3) AS BTRFIT3 , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT4) AS BTRFIT4 , BI.BTRFCC1, BI.BTRFEC1, BI.BTRFPC1, BI.BTRFEP1 , BI.BTRFCC2, BI.BTRFPC2, BI.BTRFCC3, BI.BTRFPC3 , BI.BTRFCC4, BI.BTRFPC4, BI.HOLICHR, BI.HOLIPAY , BI.RCVDCKY, BI.POSHPDT, BI.POSHPTM, BI.POSHPDY , BI.RCVDCTM, BI.HOLICHR AS HOLCHOG, BI.HOLIPAY AS HOLPAOG , BI.DRVERNM , DATE_FORMAT(STR_TO_DATE(BH.BFHYYMM, '%Y%m'), '%Y-%m') as BFHYYMM , DATE_FORMAT(BI.RCVDATE, '%Y-%m-%d') AS RCVDATE , DATE_FORMAT(BH.FCDDATE, '%Y-%m-%d') AS FCDDATE , DATE_FORMAT(STR_TO_DATE(BH.FCDTIME, '%H%i%s'), '%H:%i:%s') AS FCDTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.FCDUSER) AS FCDUSER , BH.FCVRFYN, MO.VONAMLC , DATE_FORMAT(BH.FCVDATE, '%Y-%m-%d') AS FCVDATE , IF(BH.FCCTIME IS NULL OR TRIM(BH.FCVTIME) = '', NULL, DATE_FORMAT(STR_TO_DATE(BH.FCVTIME, '%H%i%s'), '%H:%i:%s')) AS FCVTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.FCVUSER) AS FCVUSER , BH.FCCFMYN , DATE_FORMAT(BH.FCCDATE, '%Y-%m-%d') AS FCCDATE , IF(BH.FCCTIME IS NULL OR TRIM(BH.FCCTIME) = '', NULL, DATE_FORMAT(STR_TO_DATE(BH.FCCTIME, '%H%i%s'), '%H:%i:%s')) AS FCCTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.FCCUSER) AS FCCUSER , DATE_FORMAT(BH.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(BH.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userInfo.schema}.FN_SY_USERNAM(BH.CREUSER) AS CREUSER , DATE_FORMAT(BH.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(BH.LMOTIME,'%H%i%s'),'%H:%i:%s') as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.LMOUSER) AS LMOUSER , BH.UPDTCHK FROM ${userInfo.schema}.BTRFHD BH INNER JOIN ${userInfo.schema}.MWARMA MW ON BH.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ( SELECT A.WAREKEY, A.BFHDKEY, A.RCVDCKY, A.BTRFIT1 , A.BTRFIT2, A.BTRFIT3, A.BTRFIT4, A.CALWEIG , C.DRVERNM, MAX(A.RCVDATE) AS RCVDATE , A.BTRFITC , SUM(A.BTRFCC1) AS BTRFCC1, SUM(A.BTRFEC1) AS BTRFEC1 , SUM(A.BTRFPC1) AS BTRFPC1, SUM(A.BTRFEP1) AS BTRFEP1 , SUM(A.BTRFCC2) AS BTRFCC2, SUM(A.BTRFPC2) AS BTRFPC2 , SUM(A.BTRFCC3) AS BTRFCC3, SUM(A.BTRFPC3) AS BTRFPC3 , SUM(A.BTRFCC4) AS BTRFCC4, SUM(A.BTRFPC4) AS BTRFPC4 , SUM(A.HOLICHR) AS HOLICHR, SUM(A.HOLIPAY) AS HOLIPAY , SUM(CASE WHEN A.CALWEIG = #{param.grossWgName} THEN A.GROSSWG ELSE A.SKUWEIG END) AS TOTALWG, MAX(A.BTRFCH1) AS BTRFCH1, MAX(A.BTRFPA1) AS BTRFPA1, DATE_FORMAT(B.POSHPDT,'%Y-%m-%d') AS POSHPDT , B.POSHPDY, DATE_FORMAT(STR_TO_DATE(B.POSHPTM, '%H%i%s'),'%H:%i:%s') AS POSHPTM, DATE_FORMAT(STR_TO_DATE(B.RCVDCTM, '%H%i%s'),'%H:%i:%s') AS RCVDCTM FROM ${userInfo.schema}.BTRFIT A INNER JOIN ${userInfo.schema}.WRCVIT B ON B.WAREKEY = A.WAREKEY AND B.RCVDCKY = A.RCVDCKY AND B.RCVDCIT = A.RCVDCIT INNER JOIN ${userInfo.schema}.WRCVHD C ON C.RCVDCKY = B.RCVDCKY AND C.WAREKEY = B.WAREKEY WHERE A.WAREKEY = #{param.warekey} GROUP BY A.WAREKEY, A.BFHDKEY, A.RCVDCKY, A.BTRFIT1 , A.BTRFIT2, A.BTRFIT3, A.BTRFIT4, A.CALWEIG , C.DRVERNM ) BI ON BI.WAREKEY = BH.WAREKEY AND BI.BFHDKEY = BH.BFHDKEY INNER JOIN ${userInfo.commonSchema}.MVOWMA MO ON MO.VOWNKEY = BH.VOWNKEY AND MO.VOUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA MV ON MV.VOWNKEY = BH.VOWNKEY AND MV.VEHICKY = BH.VEHICKY AND MV.VHUSEYN = 'Y'
AND BH.WAREKEY = #{param.warekey}
AND BI.RCVDCKY LIKE CONCAT ('%', #{param.rcvdcky}, '%')
AND BH.FCDDATE >= #{param.fcddatefrom}
AND BH.FCDDATE <= #{param.fcddateto}
AND BH.FCDDATE BETWEEN #{param.fcddatefrom} AND #{param.fcddateto}
AND BH.FCVDATE >= #{param.fcvdatefrom}
AND BH.FCVDATE <= #{param.fcvdateto}
AND BH.FCVDATE BETWEEN #{param.fcvdatefrom} AND #{param.fcvdateto}
AND BH.FCVRFYN = #{param.fcvrfyn}
AND BH.${param.btrstat} = 'Y' AND BH.FCCFMYN = 'N'
AND BH.FCVRFYN = 'Y' AND BH.${param.btrstat} = 'Y'
ORDER BY BH.BFHDKEY DESC

/* selectBtrfitList */ SELECT CONCAT(BI.BFHDKEY,BI.BFHDCIT) AS ROWKEY , BC.BTRCNAM , BI.WAREKEY, BI.BFHDKEY, BI.BFHDCIT, BI.BTRCATE , BI.DOCCATE, BI.DOCTYPE, BI.BTRFITC, BI.BTRFITN , BI.OWNERKY, BI.OWNRNAM, BI.CUSTCOD, BI.CUSTNAM , BI.SKUMKEY, BI.BTRFIGB, BI.BTRFICT , BI.SKUTHIC, BI.SKULENG, BI.SKUWIDT, BI.SKUWEIG , BI.GROSSLN, BI.GROSSWD, BI.GROSSWG, BI.CALWEIG , DATE_FORMAT(BI.RCVDATE , '%Y-%m-%d') AS RCVDATE , BI.RCVDCKY, BI.ADDCOKY, BI.BTRFKY1 , BI.BTRFCH1, BI.BTRFCC1, BI.BTRFPA1, BI.BTRFPC1 , BI.BTRFEC1, BI.BTRFEP1, BI.BTRFKY2, BI.BTRFCH2 , BI.BTRFCC2, BI.BTRFPA2, BI.BTRFPC2, BI.BTRFKY3 , BI.BTRFCH3, BI.BTRFCC3, BI.BTRFPA3, BI.BTRFPC3 , BI.BTRFKY4, BI.BTRFCH4, BI.BTRFCC4, BI.BTRFPA4 , BI.BTRFPC4, BI.SURCHCO, BI.ADDCHCO, BI.ADDPACO , BI.HOLICHR, BI.HOLIPAY, BI.TOTITCH, BI.TOTITPA , BI.ADCMEMO, BI.BTRFCBT, BI.SBILLTO, BA.ADCOPER , (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = BI.SBILLTO AND CUDELYN = 'Y' ) AS SBILLNM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'STNWEIG' AND CDATTR1 = BI.CALWEIG) AS CALWGNM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = BA.ADDSIKY) AS ADCONAM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT1) AS BTRFIT1 , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT2) AS BTRFIT2 , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT3) AS BTRFIT3 , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRFITM' AND COMCDVL = BI.BTRFIT4) AS BTRFIT4 , MV.VONAMLC AS BTRFPAT, MD.DOCCTNM, MD.DOCTYNM, MW.WHNAMLC, MVC.VHCFNAM , BH.TRFDFCH , BH.TRFDFPA
, DATE_FORMAT(WI.POSHPDT, '%Y-%m-%d') AS POSHPDT , DATE_FORMAT(STR_TO_DATE(WI.POSHPTM, '%H%i%s'),'%H:%i:%s') AS POSHPTM , WI.POSHPDY, WI.INVOICE, WI.BTRFSTC , WI.DEORGNM, WI.DEMODNM, WI.DEMDMAN, WI.DEMDADR , WI.DEMPOCD, WI.DEMDTLN , (SELECT RENAMLC FROM ${userInfo.schema}.MREGMA WHERE REGIKEY = WI.REGIORG AND REUSEYN = 'Y') AS REORGNM , (SELECT RENAMLC FROM ${userInfo.schema}.MREGMA WHERE REGIKEY = WI.REGIMOD AND REUSEYN = 'Y') AS REMODNM , DATE_FORMAT(WI.RCVDCDT, '%Y-%m-%d') AS RCVDCDT , DATE_FORMAT(STR_TO_DATE(WI.RCVDCTM, '%H%i%s'), '%H:%i:%s') AS RCVDCTM , WI.REGIORG, WI.REGIMOD , (SELECT RENAMLC FROM ${userInfo.schema}.MREGMA WHERE REGIKEY = WI.REGIORG) AS RENAMLC , DATE_FORMAT(BH.FCCDATE,'%Y-%m-%d') AS FCCDATE , DATE_FORMAT(STR_TO_DATE(BH.FCCTIME,'%H%i%s'),'%H:%i:%s') AS FCCTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.FCCUSER) AS FCCUSER , DATE_FORMAT(BI.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(BI.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userInfo.schema}.FN_SY_USERNAM(BI.CREUSER) AS CREUSER , DATE_FORMAT(BI.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(BI.LMOTIME,'%H%i%s'),'%H:%i:%s') as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(BI.LMOUSER) AS LMOUSER , BI.UPDTCHK FROM ${userInfo.schema}.BTRFIT BI INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = BI.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.WRCVIT WI ON WI.WAREKEY = BI.WAREKEY AND WI.RCVDCKY = BI.RCVDCKY AND WI.RCVDCIT = BI.RCVDCIT AND WI.BTRCATE = BI.BTRCATE AND WI.ITEMCOD = BI.BTRFITC AND WI.SKUMKEY = BI.SKUMKEY AND WI.OWNERKY = BI.OWNERKY INNER JOIN ${userInfo.schema}.BADDCO BA ON BA.ADDCOKY = WI.ADDCOKY INNER JOIN ${userInfo.commonSchema}.MVOWMA MV ON MV.VOWNKEY = BI.BTRFPAT AND MV.VOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.DOCCATE = BI.DOCCATE AND MD.DOCTYPE = BI.DOCTYPE AND MD.WAREKEY = BI.WAREKEY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE AND BC.TFONLYN = 'N' INNER JOIN ${userInfo.schema}.BTRFHD BH ON BH.WAREKEY = BI.WAREKEY AND BH.BFHDKEY = BI.BFHDKEY INNER JOIN ${userInfo.commonSchema}.MVHCMA MVC ON MVC.VOWNKEY = BH.VOWNKEY AND MVC.VEHICKY = BH.VEHICKY
AND BI.WAREKEY = #{param.warekey}
AND BI.RCVDCKY LIKE CONCAT('%', #{param.rcvdcky}, '%')
AND BI.BFHDKEY LIKE CONCAT('%', #{param.bfhdkey}, '%')
AND BI.BTRCATE = #{param.btrcate}
AND BI.BTRFITC = #{param.itemcod}
AND BI.BTRFCBT = #{param.btrfcbt}
AND MVC.VEHICKY = #{param.btrfpat}
AND BI.SBILLTO = #{param.sbillto}
AND BA.ADDSIKY = #{param.addsiky}
AND BI.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
AND WI.DEORGNM LIKE CONCAT ('%',#{param.deorgnm},'%')
AND BI.SKUMKEY IN
#{skumkey}
AND BH.FCDDATE >= #{param.fcddatefrom}
AND BH.FCDDATE <= #{param.fcddateto}
AND BH.FCDDATE BETWEEN #{param.fcddatefrom} AND #{param.fcddateto}
AND BH.FCVRFYN = #{param.fcvrfyn}
AND BH.FCCDATE >= #{param.confirmdatefrom}
AND BH.FCCDATE <= #{param.confirmdateto}
AND BH.FCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
AND BH.FCCFMYN = #{param.fccfmyn}
ORDER BY BI.BFHDKEY, BI.BFHDCIT

