	UPDATE ${userInfo.schema}.BTRFHD
	   SET TRFDFSD = #{param.trfdfsd}
	     , TRFDFWG = #{param.trfdfwg}
	     , TRFDFCH = #{param.trfdfch}
	     , TRFDFPA = #{param.trfdfpa}
	     , TOORGCH = #{param.toorgch}
	     , TOORGPA = #{param.toorgpa}
	     , TOSURCH = #{param.tosurch}
	     , TOSURPA = #{param.tosurpa}
	     , TOTCHCO = #{param.totchco}
	     , TOTPACO = #{param.totpaco}
	     , BFHMEMO = #{param.bfhmemo}
	     , FCVRFYN = #{param.fcvrfyn}
	     , FCVDATE = TO_CHAR(CURRENT_TIMESTAMP(), "YYYYMMDD")
	     , FCVTIME = TO_CHAR(CURRENT_TIMESTAMP(), "HH24MISS")
	     , FCVUSER = #{userInfo.useract}
	     , LMODATE = TO_CHAR(CURRENT_TIMESTAMP(), "YYYYMMDD")
	     , LMOTIME = TO_CHAR(CURRENT_TIMESTAMP(), "HH24MISS")
	     , LMOUSER = #{userInfo.useract}
	     , UPDTCHK = #{param.updtchk} + 1
	WHERE WAREKEY = #{param.warekey}
	  AND BFHDKEY = #{param.bfhdkey}
	  AND UPDTCHK = #{param.updtchk}

/* updateBtrfitList */
UPDATE ${userInfo.schema}.BTRFIT
   SET SURCHCO = #{param.surchco}
     , ADDCHCO = #{param.addchco}
     , HOLICHR = #{param.holichr}
     , HOLIPAY = #{param.holipay}
     , TOTITCH = BTRFCC1 + BTRFEC1 + BTRFCC2 + BTRFCC3 + BTRFCC4 + #{param.surchco} + #{param.addchco} + #{param.holichr}
     , ADDPACO = #{param.addpaco}
     , TOTITPA = BTRFPC1 + BTRFEP1 + BTRFPC2 + BTRFPC3 + BTRFPC4 + #{param.addpaco} + #{param.holipay}
     , ADCMEMO = ifnull(#{param.adcmemo},'')
     , BTRFCBT = #{param.btrfcbt}
     , SBILLTO = #{param.sbillto}
     , LMODATE = TO_CHAR(CURRENT_TIMESTAMP(), "YYYYMMDD")
     , LMOTIME = TO_CHAR(CURRENT_TIMESTAMP(), "HH24MISS")
     , LMOUSER = #{userInfo.useract}
     , UPDTCHK = #{param.updtchk} + 1
 WHERE BFHDKEY = #{param.bfhdkey}
   AND BFHDCIT = #{param.bfhdcit}
   AND UPDTCHK = #{param.updtchk}

