  AND UPDTCHK = #{param.updtchk}

/* updateBtrfhdConfirm */
UPDATE ${userInfo.schema}.BTRFHD
   SET FCCFMYN = #{param.fccfmyn}
     , FCCDATE = TO_CHAR(CURRENT_TIMESTAMP(),"YYYYMMDD")
     , FCCTIME = TO_CHAR(CURRENT_TIMESTAMP(),"HH24MISS")
     , FCCUSER = #{userInfo.useract}
     , LMODATE = TO_CHAR(CURRENT_TIMESTAMP(), "YYYYMMDD")
     , LMOTIME = TO_CHAR(CURRENT_TIMESTAMP(), "HH24MISS")
     , LMOUSER = #{userInfo.useract}
     , UPDTCHK = #{param.updtchk} + 1
 WHERE WAREKEY = #{param.warekey}
   AND BFHDKEY = #{param.bfhdkey}
   AND UPDTCHK = #{param.updtchk}

UPDATE ${userInfo.schema}.BTRFHD
   SET PAYADYN = IFNULL(#{param.payadyn},'N')
	 , UPDTCHK = #{param.updtchk} + 1
 WHERE WAREKEY = #{param.warekey}
   AND BFHDKEY = #{param.bfhdkey}
   AND UPDTCHK = #{param.updtchk}
   AND FCCFMYN = 'Y'

UPDATE ${userInfo.schema}.WRCVHD
   SET PAYADYN = IFNULL(#{param.payadyn},'N')
	 , UPDTCHK = UPDTCHK + 1
 WHERE WAREKEY = #{param.warekey}
   AND RCVDCKY = #{param.rcvdcky}
   AND ICLOHKY = #{param.bfhdkey}
   AND ICLOSYN = 'Y'
   AND UPDTCHK = (SELECT UPDTCHK FROM ${userInfo.schema}.WRCVHD WHERE WAREKEY = #{param.warekey} AND RCVDCKY = #{param.rcvdcky})

mapper.select:
/* selectDoe084VerifySummary */ SELECT CONCAT(BI.WAREKEY, BI.BTRCATE, BI.BTRFIGB) AS ROWKEY , BI.WAREKEY, BC.BTRCNAM AS BTRCATE, BI.BTRFIGB , SUM(SKUWEIG) AS TOTALWG , SUM(BI.TOTITCH) AS TOTALCH , SUM(BI.TOTITPA) AS TOTALPA , SUM(BI.BTRFCC1) AS TOTCIT1 , SUM(BI.BTRFCC2) AS TOTCIT2 , SUM(BI.BTRFCC3) AS TOTCIT3 , SUM(BI.BTRFCC4) AS TOTCIT4 , SUM(BI.BTRFPC1) AS TOTPIT1 , SUM(BI.BTRFPC2) AS TOTPIT2 , SUM(BI.BTRFPC3) AS TOTPIT3 , SUM(BI.BTRFPC4) AS TOTPIT4 , SUM(BI.BTRFEC1) AS TOTEXCH , SUM(BI.BTRFEP1) AS TOTEXPA , SUM(BI.HOLICHR) AS TOTHOCH , SUM(BI.HOLIPAY) AS TOTHOPA FROM ${userInfo.schema}.BTRFIT BI INNER JOIN ${userInfo.schema}.BTRCAT BC ON BI.BTRCATE = BC.BTRCATE AND BC.TFONLYN = 'N' INNER JOIN ${userInfo.schema}.BTRFHD BH ON BH.WAREKEY = BI.WAREKEY AND BH.BFHDKEY = BI.BFHDKEY
AND BI.WAREKEY = #{param.warekey}
AND BH.FCVDATE >= #{param.fcvdatefrom}
AND BH.FCVDATE <= #{param.fcvdateto}
AND BH.FCVDATE BETWEEN #{param.fcvdatefrom} AND #{param.fcvdateto}
AND BH.FCVRFYN = 'Y'
GROUP BY BI.WAREKEY, BI.BTRCATE, BC.BTRCNAM, BI.BTRFIGB ORDER BY BI.WAREKEY, BI.BTRCATE, BC.BTRCNAM, BI.BTRFIGB

mapper.sql:
SELECT CONCAT(TI.VHPLNKY, TI.VHPLNIT) AS ROWKEY, TI.WAREKEY, TI.VHPLNKY, TI.VHPLNIT , TH.VOWNKEY, VO.VOWAFFI, TH.DOCCATE, TH.DOCTYPE , MD.DOCCTNM, MD.DOCTYNM, TI.SKUMKEY, TI.SKUDESC , TI.ITEMCOD AS BTRPITC, MI.CDCATE2 AS BTRPIGB , MI.CDATTR1 AS BTRPICT , TI.BTRFSTC, TI.SKUTHIC , TI.SKUWIDT, TI.SKULENG, TI.SKUWEIG, TI.GROSSLN , TI.GROSSWG, TI.GROSSWD, TI.REGIORG, TI.REGIMOD , TI.TPISTAT, TI.CUSTCOD, TI.OWNERKY, TI.OWNRNAM , TI.CUSTNAM, TI.ADDCOKY, TI.DEORGNM, TI.DEMODNM , TI.DEMDMAN, TI.DEMDADR , TI.DEMPOCD, TI.DEMDTLN , DATE_FORMAT(TI.BILDATE,'%Y-%m-%d') AS BILDATE , TI.POSHPDY, DATE_FORMAT(TI.POSHPDT, '%Y-%m-%d') AS POSHPDT , DATE_FORMAT(STR_TO_DATE(TI.POSHPTM, '%H%i%s'), '%H:%i:%s') AS POSHPTM , VH.VHCFNAM, BA.ADDSIKY, TI.BTRCATE, BC.BTRCNAM , BA.ADCOPER, VO.VONAMLC, BO.BTRPKEY AS BPCHKEY , DATE_FORMAT(TI.TRNCPDT, '%Y-%m-%d') AS TRNCPDT , TI.TRNCPDT AS TRNINDT , TI.TRNCPTM AS TRNINTM , IF(TH.PAYADYN = 'Y', '선지급완료', '') AS PAYADST , TH.PAYADYN, DATE_FORMAT(STR_TO_DATE(TI.TRNCPTM, '%H%i%s'), '%H:%i:%s') AS TRNCPTM , IFNULL(BO.BTRPITM, #{param.btrpitm}) AS BTRPITM , BO.BTRPITN , DATE_FORMAT(WS.SPEIDAT,'%Y-%m-%d') AS SPEIDAT , DATE_FORMAT(STR_TO_DATE(WS.SPEITIM,'%H%i%s'),'%H:%i:%s') AS SPEITIM , (SELECT RENAMLC FROM ${userInfo.schema}.MREGMA WHERE REGIKEY = TI.REGIORG AND REUSEYN = 'Y') AS REORGNM , (SELECT RENAMLC FROM ${userInfo.schema}.MREGMA WHERE REGIKEY = TI.REGIMOD AND REUSEYN = 'Y') AS REMODNM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRPITM' AND COMCDVL = IFNULL(BO.BTRPITM,#{param.btrpitm})) AS BILLITM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = BA.ADDSIKY) AS ADCONAM , ( CASE WHEN (COALESCE(BO.STNWEIG, '') = #{param.stnweig} OR BO.STNWEIG IS NULL) THEN #{param.grossWgName} ELSE #{param.skuWeigName} END ) AS CALWEIG
, BP.BPPAKEY AS BPPAKEY , BP.BTRPPAT AS BTRPPAT , BP.BTRPPAY AS BTRPPAY , BP.BTRPPCO AS BTRPPCO , BP.BTRPEPC AS BTRPEPC , BP.TOTITPA AS TOTITPA , BP.HOLIPAY AS HOLIPAY , DATE_FORMAT(BP.CREDATE,'%Y-%m-%d') AS PAYADDT
, PO.BTRPKEY AS BPPAKEY , TH.VOWNKEY AS BTRPPAT , ( CASE WHEN PO.REGIKEY IS NOT NULL AND PO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = PO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) WHEN PO.REGIKEY IS NOT NULL AND PO.SIZGBYN = 'N' THEN PO.BTRPPAY ELSE PO.BTRPPAY END ) AS BTRPPAY , ( CASE WHEN PO.REGIKEY IS NOT NULL AND PO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = PO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) WHEN PO.REGIKEY IS NOT NULL AND PO.SIZGBYN = 'N' THEN PO.BTRPPAY ELSE PO.BTRPPAY END * CASE WHEN PO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) AS BTRPPCO_CAL , ( CASE WHEN PO.REGIKEY IS NOT NULL AND PO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = PO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) WHEN PO.REGIKEY IS NOT NULL AND PO.SIZGBYN = 'N' THEN PO.BTRPPAY ELSE PO.BTRPPAY END * CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) * BA.ADCOPER AS BTRPEPC_CAL , ( CASE WHEN TH.DOCTYPE = '810' AND (WEEKDAY(TI.POSHPDT) IN (5,6) OR ( TIME(TI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(MW.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(TI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(MW.HOLTMTO, '%H%i%s'), '%H%i%s') )) THEN ( CASE WHEN PO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = PO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE PO.BTRPPAY END ) * ( CASE WHEN PO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) * (MW.HOLRATE / 100) ELSE 0 END ) AS HOLIPAY
, BO.BTRPCHR AS BTRPCHR , IFNULL(BO.BTRPCHR, 0) * ( CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) AS BTRPCCO_CAL , IFNULL(BO.BTRPCHR, 0) * ( CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) * BA.ADCOPER AS BTRPECC_CAL , COALESCE( CASE WHEN TI.REGIORG != TI.REGIMOD AND BO.BTRPCHR < PO.BTRPCHR THEN ( PO.BTRPCHR * ( CASE WHEN PO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) ) - ( BO.BTRPCHR * ( CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) ) END , 0) AS SURCHCO_CAL , ( CASE WHEN
TH.DOCTYPE = '810' AND (WEEKDAY(TI.POSHPDT) IN (5,6) OR ( TIME(TI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(MW.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(TI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(MW.HOLTMTO, '%H%i%s'), '%H%i%s') )) THEN BO.BTRPCHR * ( CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) * (MW.HOLRATE / 100) ELSE 0 END ) AS HOLICHR , IFNULL( (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = BC.BTRPBTP) , ( CASE WHEN TRIM(TI.OWNERKY) != '' OR TI.OWNERKY IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = TI.OWNERKY) WHEN TRIM(TI.OWNRNAM) != '' OR TI.OWNRNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = TI.OWNRNAM LIMIT 1) WHEN TRIM(TI.CUSTNAM) != '' OR TI.CUSTNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = TI.CUSTNAM LIMIT 1) ELSE '' END ) ) AS BTRPCBT , ( CASE WHEN TRIM(TI.OWNERKY) != '' OR TI.OWNERKY IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = TI.OWNERKY AND SURCHYN = 'Y') WHEN TRIM(TI.OWNRNAM) != '' OR TI.OWNRNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = TI.OWNRNAM AND SURCHYN = 'Y' LIMIT 1) WHEN TRIM(TI.CUSTNAM) != '' OR TI.CUSTNAM IS NOT NULL THEN (SELECT CUSTKEY FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = TI.CUSTNAM AND SURCHYN = 'Y' LIMIT 1) ELSE '' END ) AS SBILLTO , ( CASE WHEN TRIM(TI.OWNERKY) != '' OR TI.OWNERKY IS NOT NULL THEN (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = TI.OWNERKY AND SURCHYN = 'Y') WHEN TRIM(TI.OWNRNAM) != '' OR TI.OWNRNAM IS NOT NULL THEN (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = TI.OWNRNAM AND SURCHYN = 'Y' LIMIT 1) WHEN TRIM(TI.CUSTNAM) != '' OR TI.CUSTNAM IS NOT NULL THEN (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUNAMLC = TI.CUSTNAM AND SURCHYN = 'Y' LIMIT 1) ELSE '' END ) AS SBILLNM , DATE_FORMAT(TI.CREDATE, '%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(TI.CRETIME, '%H%i%s'), '%H:%i:%s') AS CRETIME , ${userInfo.schema}.FN_SY_USERNAM(TI.CREUSER) AS CREUSER , DATE_FORMAT(TI.LMODATE, '%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(TI.LMOTIME, '%H%i%s'), '%H:%i:%s') AS LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(TI.LMOUSER) AS LMOUSER , TI.UPDTCHK FROM ${userInfo.schema}.TPLNIT TI LEFT JOIN ${userInfo.schema}.WSHPIT WS ON WS.WAREKEY = TI.WAREKEY AND WS.SKUMKEY = TI.SKUMKEY INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = TI.WAREKEY INNER JOIN ${userInfo.schema}.TPLNHD TH ON TH.WAREKEY = TI.WAREKEY AND TH.VHPLNKY = TI.VHPLNKY INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = TI.BTRCATE AND BC.PFONLYN = 'N' INNER JOIN ${userInfo.schema}.BADDCO BA ON BA.ADDCOKY = TI.ADDCOKY INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = TH.WAREKEY AND MD.DOCCATE = TH.DOCCATE AND MD.DOCTYPE = TH.DOCTYPE INNER JOIN ${userInfo.schema}.MCODEM MI ON MI.COMCDKY = 'ITEMCOD' AND MI.COMCDVL = TI.ITEMCOD INNER JOIN ${userInfo.commonSchema}.MVOWMA VO ON VO.VOWNKEY = TH.VOWNKEY AND VOUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA VH ON VH.VOWNKEY = VO.VOWNKEY AND VH.VEHICKY = TH.VEHICKY AND VH.VHUSEYN = 'Y'
LEFT JOIN ( SELECT WAREKEY, BTRCATE, BTRPKEY, REGIKEY , BTRPITC, BTRPITM, BTRPITN, BTRPIGB , BTRPICT, STNWEIG, BTRPVAF, BTRPCHR , BTRPPAY, BTRPEYN, BTRDFYN, BTRPDAF , BTRPDAT FROM ${userInfo.schema}.BTRPMA BP WHERE WAREKEY = #{param.warekey} ) BO ON BO.WAREKEY = TI.WAREKEY AND BO.BTRCATE = TI.BTRCATE AND BO.BTRPVAF = VO.VOWAFFI AND BO.REGIKEY = TI.REGIORG AND BO.BTRPITC = TI.ITEMCOD AND (DATE_FORMAT(TI.POSHPDT,'%Y%m') BETWEEN BO.BTRPDAF AND BO.BTRPDAT)
LEFT JOIN ( SELECT WAREKEY, BTRCATE, BTRPKEY, REGIKEY , BTRPITC, STNWEIG, BTRPVAF, BTRPCHR , BTRPPAY, BTRPEYN, SIZGBYN, BTRDFYN , BTRPDAF, BTRPDAT FROM ${userInfo.schema}.BTRPMA BP WHERE WAREKEY = #{param.warekey} ) PO ON PO.WAREKEY = TI.WAREKEY AND PO.BTRCATE = TI.BTRCATE AND PO.BTRPVAF = VO.VOWAFFI AND PO.REGIKEY = TI.REGIMOD AND PO.BTRPITC = TI.ITEMCOD AND (DATE_FORMAT(TI.BILDATE,'%Y%m') BETWEEN PO.BTRPDAF AND PO.BTRPDAT)
INNER JOIN ${userInfo.schema}.BPPAIT BP ON BP.WAREKEY = TI.WAREKEY AND BP.VHPLNKY = TI.VHPLNKY AND BP.VHPLNIT = TI.VHPLNIT
WHERE TH.TPNSTAT IN ('FINISH','INVCMP') AND TI.TPISTAT IN ('ARRIVE','INVCMP') AND TH.TCLOSYN = 'N'
AND TH.PAYADYN = #{param.payadyn}
AND TI.WAREKEY = #{param.warekey}
AND TH.DOCTYPE = #{param.doctype}
AND VH.VHCFNAM LIKE CONCAT('%',#{param.vhcfnam},'%')
AND TI.ADDSIKY = #{param.addsiky}
AND TI.BILDATE >= #{param.bildatefrom}
AND TI.BILDATE <= #{param.bildateto}
