/* selectDoe085List */ WITH CALCULATED_VALUES AS (
) SELECT
CV.BTRPPCO , CV.BTRPEPC , CV.HOLIPAY , CV.TOTITPA
FLOOR(CV.BTRPPCO_CAL / 1000) AS BTRPPCO , FLOOR(CV.BTRPEPC_CAL / 1000) AS BTRPEPC , FLOOR(CV.HOLIPAY/1000) AS HOLIPAY , FLOOR((CV.BTRPPCO_CAL + CV.BTRPEPC_CAL + CV.HOLIPAY) / 1000) AS TOTITPA
, FLOOR(CV.BTRPCCO_CAL / 1000) AS BTRPCCO , FLOOR(CV.BTRPECC_CAL / 1000) AS BTRPECC , FLOOR(CV.HOLICHR / 1000) AS HOLICHR , FLOOR((CV.BTRPCCO_CAL + CV.BTRPECC_CAL + CV.HOLICHR + CV.SURCHCO_CAL) / 1000) AS TOTITCH , FLOOR(CV.SURCHCO_CAL / 1000) AS SURCHCO , IFNULL( (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = CV.BTRPCBT), (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = CV.OWNERKY)) AS BTRPBTP , CV.BTRPCBT , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'TPISTAT' AND COMCDVL = CV.TPISTAT) AS TPISTAT , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = CV.ADDSIKY) AS ADCONAM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'STNWEIG' AND CDATTR1 = CV.CALWEIG) AS CALWGNM , CV.* FROM CALCULATED_VALUES CV ORDER BY CV.VHPLNKY, CV.VHPLNIT ASC

