mapper.select:
/* selectBtrphdList */ SELECT BH.BPHDKEY AS ROWKEY, BH.DFSTDCH, BH.DFSTDPA , BH.WAREKEY, BH.BPHDKEY, BH.VOWNKEY, BH.VEHICKY , BH.TRPDFSD, BH.TRPDFWG, BH.TRPDFCH, BH.TRPDFPA , BH.TOORGCH, BH.TOSURCH, BH.TOTCHCO, BH.TOORGPA , BH.TOSURPA, BH.TOTPACO, BH.BPHMEMO, MW.WHNAMLC , MV.VHCFNAM, BI.TOTALWG AS TOTALWG , TH.DOCTYPE , MD.DOCTYNM, TH.PAYADYN, TH.PAYADYN AS PAYADOG, TH.PAYADYN AS PAYADMD , IF(BI.HOLICHR > 0 OR BI.HOLIPAY > 0, 'Y', 'N') AS HOLIDYN , MW.HOLRATE , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRPITM' AND COMCDVL = BI.BTRPITM) AS BTRPITM , BI.BTRPCCO, BI.BTRPECC, BI.BTRPPCO, BI.BTRPEPC , BI.HOLICHR, BI.HOLIPAY, BI.HOLICHR AS HOLCHOG, BI.HOLIPAY AS HOLPAOG , BI.VHPLNKY, TH.DRVERNM, MW.WHNAMLC , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'VOWAFFI' AND COMCDVL = MO.VOWAFFI) AS VOWAFFI , DATE_FORMAT(STR_TO_DATE(BH.BPHYYMM, '%Y%m'), '%Y-%m') AS BPHYYMM , DATE_FORMAT(BI.TRNINDT, '%Y-%m-%d') AS TRNINDT , DATE_FORMAT(BH.PCDDATE, '%Y-%m-%d') AS PCDDATE , DATE_FORMAT(STR_TO_DATE(BH.PCDTIME, '%H%i%s'), '%H:%i:%s') AS PCDTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.PCDUSER) AS PCDUSER , BH.PCVRFYN, MO.VONAMLC , DATE_FORMAT(BH.PCVDATE, '%Y-%m-%d') AS PCVDATE , IF(BH.PCCTIME IS NULL OR TRIM(BH.PCVTIME) = '', NULL, DATE_FORMAT(STR_TO_DATE(BH.PCVTIME, '%H%i%s'), '%H:%i:%s')) AS PCVTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.PCVUSER) AS PCVUSER , BH.PCCFMYN , DATE_FORMAT(BH.PCCDATE, '%Y-%m-%d') AS PCCDATE , IF(BH.PCCTIME IS NULL OR TRIM(BH.PCCTIME) = '', NULL, DATE_FORMAT(STR_TO_DATE(BH.PCCTIME, '%H%i%s'), '%H:%i:%s')) AS PCCTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.PCCUSER) AS PCCUSER , MV.DRVERNM , DATE_FORMAT(BH.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(BH.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userInfo.schema}.FN_SY_USERNAM(BH.CREUSER) AS CREUSER , DATE_FORMAT(BH.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(BH.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.LMOUSER) AS LMOUSER , BH.UPDTCHK FROM ${userInfo.schema}.BTRPHD BH INNER JOIN ${userInfo.schema}.MWARMA MW ON BH.WAREKEY = MW.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ( SELECT WAREKEY, BPHDKEY, VHPLNKY, BTRPITM , CALWEIG, MAX(TRNINDT) AS TRNINDT , SUM(BTRPCCO) AS BTRPCCO, SUM(BTRPECC) AS BTRPECC , SUM(BTRPPCO) AS BTRPPCO, SUM(BTRPEPC) AS BTRPEPC , SUM(HOLICHR) AS HOLICHR, SUM(HOLIPAY) AS HOLIPAY , SUM(SURCHCO) AS SURCHCO, SUM(ADDCHCO) AS ADDCHCO , SUM(ADDPACO) AS ADDPACO, SUM(GROSSWG) AS GROSSWG , SUM(SKUWEIG) AS SKUWEIG , SUM(CASE WHEN CALWEIG = #{param.grossWgName} THEN GROSSWG ELSE SKUWEIG END) AS TOTALWG FROM ${userInfo.schema}.BTRPIT WHERE WAREKEY = #{param.warekey} GROUP BY WAREKEY, BPHDKEY, VHPLNKY, BTRPITM , CALWEIG ) BI ON BI.WAREKEY = BH.WAREKEY AND BI.BPHDKEY = BH.BPHDKEY INNER JOIN ${userInfo.schema}.TPLNHD TH ON TH.WAREKEY = BI.WAREKEY AND TH.VHPLNKY = BI.VHPLNKY INNER JOIN ${userInfo.commonSchema}.MVOWMA MO ON MO.VOWNKEY = BH.VOWNKEY AND MO.VOUSEYN = 'Y' INNER JOIN ${userInfo.commonSchema}.MVHCMA MV ON MV.VOWNKEY = BH.VOWNKEY AND MV.VEHICKY = BH.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = TH.WAREKEY AND MD.DOCCATE = TH.DOCCATE AND MD.DOCTYPE = TH.DOCTYPE
AND BH.WAREKEY = #{param.warekey}
AND BI.VHPLNKY LIKE CONCAT('%', #{param.vhplnky}, '%')
AND BH.PCDDATE >= #{param.btrpdaffrom}
AND BH.PCDDATE <= #{param.btrpdafto}
AND BH.PCDDATE BETWEEN #{param.btrpdaffrom} AND #{param.btrpdafto}
AND BH.PCVDATE >= #{param.pcvdatefrom}
AND BH.PCVDATE <= #{param.pcvdateto}
AND BH.PCVDATE BETWEEN #{param.pcvdatefrom} AND #{param.pcvdateto}
AND BH.PCVRFYN = #{param.pcvrfyn}
AND BH.PCCFMYN = 'Y'
AND BH.PCCFMYN = 'N'
ORDER BY BH.BPHDKEY DESC

/* selectBtrpitList */ SELECT CONCAT(BI.BPHDKEY, BI.BPHDCIT) AS ROWKEY, BC.BTRCNAM , BI.WAREKEY, BI.BPHDKEY, BI.BPHDCIT, BI.BTRCATE , BI.DOCCATE, BI.DOCTYPE, BI.BTRPITC, BI.BTRPITN , BI.SKUMKEY, BI.BTRPIGB, BI.BTRPICT, BI.SKUTHIC , BI.SKULENG, BI.SKUWIDT, BI.SKUWEIG, BI.GROSSLN , BI.GROSSWD, BI.GROSSWG, BI.CALWEIG, BI.VHPLNKY , BI.ADDCOKY, BI.BPCHKEY, BI.BPPAKEY, BI.BTRPCHR , BI.BTRPCCO, BI.BTRPPAY, BI.BTRPPCO, BI.BTRPECC , BI.BTRPEPC, BI.SURCHCO, BI.ADDCHCO, BI.HOLICHR , BI.HOLIPAY, BI.ADDPACO, BI.ADCMEMO, TI.CUSTCOD , BI.BPHDCIT, BI.SBILLTO, BA.ADCOPER, BI.VHPLNIT , MVC.VHCFNAM, BI.BTRPCBT, BI.BTRPCBT, BI.CUSTNAM , BI.OWNERKY , BI.OWNRNAM, BI.REGIORG, BI.REGIMOD , BI.TOTITCH , BI.TOTITPA , BH.TRPDFCH, BH.TRPDFPA , TI.DEORGNM, TI.DEMODNM , TI.DEMDMAN, TI.DEMDADR , TI.DEMPOCD, TI.DEMDTLN , IF(TH.PAYADYN = 'Y','선지급완료','') AS PAYADST, TH.PAYADYN , (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = BI.BTRPCBT AND CUDELYN = 'Y') AS BTCBTNM , (SELECT CUNAMLC FROM ${userInfo.schema}.MCUSMA WHERE CUSTKEY = BI.SBILLTO AND CUDELYN = 'Y') AS SBILLNM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = BA.ADDSIKY) AS ADCONAM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'BTRPITM' AND COMCDVL = BI.BTRPITM) AS BTRPITM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'STNWEIG' AND CDATTR1 = BI.CALWEIG) AS CALWGNM , (SELECT COMCDTX FROM ${userInfo.schema}.MCODEM WHERE COMCDKY = 'TPISTAT' AND COMCDVL = TI.TPISTAT) AS TPISTAT , (SELECT RENAMLC FROM ${userInfo.schema}.MREGMA WHERE REGIKEY = BI.REGIORG AND REUSEYN = 'Y') AS REORGNM , (SELECT RENAMLC FROM ${userInfo.schema}.MREGMA WHERE REGIKEY = BI.REGIMOD AND REUSEYN = 'Y') AS REMODNM , MV.VONAMLC AS BTRPPAT , MD.DOCCTNM ,MD.DOCTYNM , MW.WHNAMLC, TI.BTRFSTC, TI.POSHPDY , DATE_FORMAT(TI.POSHPDT, '%Y-%m-%d') AS POSHPDT , DATE_FORMAT(STR_TO_DATE(TI.POSHPTM, '%H%i%s'), '%H:%i:%s') AS POSHPTM , DATE_FORMAT(BI.TRNINDT, '%Y-%m-%d') AS TRNINDT , DATE_FORMAT(STR_TO_DATE(BI.TRNINTM, '%H%i%s'), '%H:%i:%s') AS TRNINTM , DATE_FORMAT(WS.SPEIDAT, '%Y-%m-%d') AS SPEIDAT , DATE_FORMAT(STR_TO_DATE(WS.SPEITIM, '%H%i%s'), '%H:%i:%s') AS SPEITIM , DATE_FORMAT(BH.PCCDATE,'%Y-%m-%d') AS PCCDATE , DATE_FORMAT(STR_TO_DATE(BH.PCCTIME,'%H%i%s'),'%H:%i:%s') AS PCCTIME , ${userInfo.schema}.FN_SY_USERNAM(BH.PCCUSER) AS PCCUSER , DATE_FORMAT(BI.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(BI.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userInfo.schema}.FN_SY_USERNAM(BI.CREUSER) AS CREUSER , DATE_FORMAT(BI.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(BI.LMOTIME,'%H%i%s'),'%H:%i:%s') as LMOTIME , ${userInfo.schema}.FN_SY_USERNAM(BI.LMOUSER) AS LMOUSER , BI.UPDTCHK FROM ${userInfo.schema}.BTRPIT BI INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = BI.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = BI.BTRCATE AND BC.PFONLYN = 'N' INNER JOIN ${userInfo.schema}.TPLNHD TH ON TH.WAREKEY = BI.WAREKEY AND TH.VHPLNKY = BI.VHPLNKY INNER JOIN ${userInfo.schema}.TPLNIT TI ON TI.WAREKEY = BI.WAREKEY AND TI.VHPLNKY = BI.VHPLNKY AND TI.VHPLNIT = BI.VHPLNIT AND TI.BTRCATE = BI.BTRCATE AND TI.ITEMCOD = BI.BTRPITC AND TI.SKUMKEY = BI.SKUMKEY LEFT JOIN ${userInfo.schema}.WSHPIT WS ON WS.WAREKEY = TI.WAREKEY AND WS.SKUMKEY = TI.SKUMKEY INNER JOIN ${userInfo.schema}.BADDCO BA ON BA.ADDCOKY = BI.ADDCOKY INNER JOIN ${userInfo.commonSchema}.MVOWMA MV ON MV.VOWNKEY = BI.BTRPPAT AND MV.VOUSEYN = 'Y' INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.DOCCATE = TH.DOCCATE AND MD.DOCTYPE = TH.DOCTYPE AND MD.WAREKEY = TH.WAREKEY INNER JOIN ${userInfo.schema}.BTRPHD BH ON BI.WAREKEY = BH.WAREKEY AND BI.BPHDKEY = BH.BPHDKEY INNER JOIN ${userInfo.commonSchema}.MVHCMA MVC ON MVC.VOWNKEY = BH.VOWNKEY AND MVC.VEHICKY = BH.VEHICKY
AND BI.WAREKEY = #{param.warekey}
AND BI.BPHDKEY LIKE CONCAT('%', #{param.bphdkey}, '%')
AND BI.BTRCATE = #{param.btrcate}
AND BI.BTRPITC = #{param.itemcod}
AND BI.BTRPCBT = #{param.btrfcbt}
AND MVC.VEHICKY = #{param.btrfpat}
AND BI.SBILLTO = #{param.sbillto}
AND BI.SKUMKEY IN
