AND BI.SKUMKEY LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND BH.PCDDATE >= #{param.btrpdaffrom}
AND BH.PCDDATE <= #{param.btrpdafto}
AND BH.PCDDATE BETWEEN #{param.btrpdaffrom} AND #{param.btrpdafto}
AND BH.PCVRFYN = #{param.pcvrfyn}
AND BI.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
AND TI.DEORGNM LIKE CONCAT ('%',#{param.deorgnm},'%')
AND BH.PCCDATE >= #{param.confirmdatefrom}
AND BH.PCCDATE <= #{param.confirmdateto}
AND BH.PCCDATE BETWEEN #{param.confirmdatefrom} AND #{param.confirmdateto}
AND BH.PCCFMYN = #{param.pccfmyn}
ORDER BY BI.BPHDKEY, BI.BPHDCIT

