mapper.select:
/* selectDoe087VerifySummary */ SELECT CONCAT(BI.WAREKEY, BI.BTRCATE, BI.BTRPIGB) AS ROWKEY , BI.WAREKEY, BC.BTRCNAM AS BTRCATE, BI.BTRPIGB, MC.COMCDTX , SUM(SKUWEIG) AS TOTALWG , SUM(BI.TOTITCH) AS TOTALCH , SUM(BI.TOTITPA) AS TOTALPA , SUM(BI.BTRPCCO) AS TOTCITM , SUM(BI.BTRPPCO) AS TOTPITM , SUM(BI.BTRPECC) AS TOTEXCH , SUM(BI.BTRPEPC) AS TOTEXPA , SUM(BI.HOLICHR) AS TOTHOCH , SUM(BI.HOLIPAY) AS TOTHOPA FROM ${userInfo.schema}.BTRPIT BI INNER JOIN ${userInfo.schema}.BTRCAT BC ON BI.BTRCATE = BC.BTRCATE AND BC.PFONLYN = 'N' INNER JOIN ${userInfo.schema}.BTRPHD BH ON BH.WAREKEY = BI.WAREKEY AND BH.BPHDKEY = BI.BPHDKEY INNER JOIN ${userInfo.commonSchema}.MVOWMA MV ON BH.VOWNKEY = MV.VOWNKEY INNER JOIN ${userInfo.schema}.MCODEM MC ON MC.COMCDKY = 'VOWAFFI' AND MC.COMCDVL = MV.VOWAFFI
AND BI.WAREKEY = #{param.warekey}
AND BH.PCVDATE >= #{param.pcvdatefrom}
AND BH.PCVDATE <= #{param.pcvdateto}
AND BH.PCVDATE BETWEEN #{param.pcvdatefrom} AND #{param.pcvdateto}
AND BH.PCVRFYN = 'Y'
GROUP BY BI.WAREKEY, BI.BTRCATE, BC.BTRCNAM, BI.BTRPIGB, MC.COMCDTX ORDER BY BI.WAREKEY, BI.BTRCATE, BC.BTRCNAM, BI.BTRPIGB, MC.COMCDTX

