/* selectDoe088Md8SummaryList */ WITH BTRF AS (
), WRCVTIT_LIST AS ( SELECT BC.BTRCNAM, WI.DOCCATE, WI.DOCTYPE, WI.ITEMCOD , MD.DOCCTNM, MD.DOCTYNM , SUM( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) AS DAYWEIG , TS.BTRFCHR AS BTRFCH1 , SUM(COALESCE(( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN (TS.BTRFCHR * WI.GROSSWG) ELSE (TS.BTRFCHR * WI.SKUWEIG) END), 0 )) AS BTRFCC1_CAL , COALESCE( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE TS.BTRFPAY END, 0 ) AS BTRFPA1 , SUM(COALESCE(( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE( ( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY), 0) ELSE TS.BTRFPAY END ) * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ), 0) ) AS BTRFPC1_CAL , SUM(( ( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY) , 0) ELSE TS.BTRFPAY END ) * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) * (BA.ADCOPER) )) AS BTRFEP1_CAL , SUM(COALESCE( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN (TS.BTRFCHR * WI.GROSSWG * BA.ADCOPER) ELSE (TS.BTRFCHR * WI.SKUWEIG * BA.ADCOPER) END, 0 )) AS BTRFEC1_CAL , LD.BTRFCHR AS BTRFCH2 , SUM(COALESCE( CASE WHEN LD.STNWEIG = #{param.stnweig} THEN (LD.BTRFCHR * WI.GROSSWG) ELSE (LD.BTRFCHR * WI.SKUWEIG) END, 0 )) AS BTRFCC2_CAL , ( CASE WHEN LD.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = LD.BTRFKEY AND ADDSIKY = BA.ADDSIKY) , 0) ELSE LD.BTRFPAY END ) AS BTRFPA2 , SUM(( CASE WHEN LD.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = LD.BTRFKEY AND ADDSIKY = BA.ADDSIKY) , 0) ELSE LD.BTRFPAY END ) * ( CASE WHEN LD.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END )) AS BTRFPC2_CAL , SC.BTRFCHR AS BTRFCH3 , SUM(COALESCE( CASE WHEN SC.STNWEIG = #{param.stnweig} THEN (SC.BTRFCHR * WI.GROSSWG) ELSE (SC.BTRFCHR * WI.SKUWEIG) END, 0 )) AS BTRFCC3_CAL , COALESCE( CASE WHEN SC.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = SC.BTRFKEY AND ADDSIKY = BA.ADDSIKY ) , 0) ELSE SC.BTRFPAY END, 0 ) AS BTRFPA3 , SUM(COALESCE(( CASE WHEN SC.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = SC.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE SC.BTRFPAY END ) * ( CASE WHEN SC.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END), 0 )) AS BTRFPC3_CAL , ST.BTRFCHR AS BTRFCH4 , SUM(COALESCE( CASE WHEN ST.STNWEIG = #{param.stnweig} THEN (ST.BTRFCHR * WI.GROSSWG) ELSE (ST.BTRFCHR * WI.SKUWEIG) END, 0 )) AS BTRFCC4_CAL , COALESCE( CASE WHEN ST.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = ST.BTRFKEY AND ADDSIKY = BA.ADDSIKY) , 0) ELSE ST.BTRFPAY END, 0 ) AS BTRFPA4 , SUM(COALESCE(( CASE WHEN ST.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = ST.BTRFKEY AND ADDSIKY = BA.ADDSIKY ) , 0) ELSE ST.BTRFPAY END ) * ( CASE WHEN ST.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ), 0 )) AS BTRFPC4_CAL ,SUM( CASE WHEN WEEKDAY(WI.POSHPDT) IN (5,6) OR ( TIME(WI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(WA.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(WI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(WA.HOLTMTO, '%H%i%s'), '%H%i%s') ) THEN TS.BTRFCHR * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) * (WA.HOLRATE / 100) ELSE 0 END ) AS HOLICHR , SUM( CASE WHEN WEEKDAY(WI.POSHPDT) IN (5,6) OR ( TIME(WI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(WA.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(WI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(WA.HOLTMTO, '%H%i%s'), '%H%i%s') ) THEN ( CASE WHEN TS.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = TS.BTRFKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE TS.BTRFPAY END ) * ( CASE WHEN TS.STNWEIG = #{param.stnweig} THEN COALESCE(WI.GROSSWG, 0) ELSE COALESCE(WI.SKUWEIG, 0) END ) * (WA.HOLRATE / 100) ELSE 0 END ) AS HOLIPAY FROM ${userInfo.schema}.WRCVIT WI INNER JOIN ${userInfo.schema}.WRCVHD WH ON WH.WAREKEY = WI.WAREKEY AND WH.RCVDCKY = WI.RCVDCKY AND WH.DOCCATE = '400' AND WH.DOCTYPE != '490' INNER JOIN ${userInfo.schema}.MWARMA WA ON WA.WAREKEY = WI.WAREKEY AND WA.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = WI.BTRCATE AND BC.TFONLYN = 'N' INNER JOIN ${userInfo.schema}.BADDCO BA ON BA.ADDCOKY = WI.ADDCOKY INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = WI.WAREKEY AND MD.DOCCATE = WI.DOCCATE AND MD.DOCTYPE = WI.DOCTYPE LEFT JOIN BTRF TS ON TS.WAREKEY = WI.WAREKEY AND TS.BTRCATE = WI.BTRCATE AND TS.BTRFITC = WI.ITEMCOD AND TS.BTRFITM = #{param.transfer} AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN TS.BTRFDAF AND TS.BTRFDAT) LEFT JOIN BTRF LD ON LD.WAREKEY = WI.WAREKEY AND LD.BTRCATE = WI.BTRCATE AND LD.BTRFITC = WI.ITEMCOD AND LD.BTRFITM = #{param.loading} AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN LD.BTRFDAF AND LD.BTRFDAT) LEFT JOIN BTRF SC ON SC.WAREKEY = WI.WAREKEY AND SC.BTRCATE = WI.BTRCATE AND SC.BTRFITC = WI.ITEMCOD AND SC.BTRFSTC = WI.BTRFSTC AND SC.BTRFITM = #{param.selection} AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN SC.BTRFDAF AND SC.BTRFDAT) LEFT JOIN BTRF ST ON ST.WAREKEY = WI.WAREKEY AND ST.BTRCATE = WI.BTRCATE AND ST.BTRFITC = WI.ITEMCOD AND ST.BTRFITM = #{param.storage} AND (DATE_FORMAT(WI.POSHPDT , '%Y%m') BETWEEN ST.BTRFDAF AND ST.BTRFDAT)
AND WI.WAREKEY = #{param.warekey}
AND WI.RCVDCDT >= #{param.poshpdtfrom}
AND WI.RCVDCDT <= #{param.poshpdtto}
AND WI.RCVDCDT BETWEEN #{param.poshpdtfrom} AND #{param.poshpdtto}
AND WH.RCVDCST = 'RVCMP' AND WI.RCVITST IN ('RVCOMP','RETURN')
GROUP BY BC.BTRCNAM, WI.DOCCATE, WI.DOCTYPE, WI.ITEMCOD , MD.DOCCTNM, MD.DOCTYNM, TS.BTRFCHR, BTRFPA1, LD.BTRFCHR , BTRFPA2, SC.BTRFCHR, BTRFPA3, ST.BTRFCHR, BTRFPA4 ),
TPLNIT_LIST AS ( SELECT BC.BTRCNAM, TH.DOCCATE, TH.DOCTYPE, TI.ITEMCOD , MD.DOCCTNM, MD.DOCTYNM , SUM(( CASE WHEN PO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END )) AS DAYWEIG , ( CASE WHEN BO.REGIKEY IS NOT NULL AND BO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = BO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) WHEN BO.REGIKEY IS NOT NULL AND BO.SIZGBYN = 'N' THEN BO.BTRPPAY ELSE PO.BTRPPAY END ) AS BTRPPAY , SUM(( CASE WHEN BO.REGIKEY IS NOT NULL AND BO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = BO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) WHEN BO.REGIKEY IS NOT NULL AND BO.SIZGBYN = 'N' THEN BO.BTRPPAY ELSE PO.BTRPPAY END * ( CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) )) AS BTRPPCO_CAL , SUM(( CASE WHEN BO.REGIKEY IS NOT NULL AND BO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = BO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) WHEN BO.REGIKEY IS NOT NULL AND BO.SIZGBYN = 'N' THEN BO.BTRPPAY ELSE PO.BTRPPAY END * ( CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) )) * (BA.ADCOPER) AS BTRPEPC_CAL , PO.BTRPCHR AS BTRPCHR , SUM(IFNULL(PO.BTRPCHR, 0) * ( CASE WHEN PO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END )) AS BTRPCCO_CAL , SUM(IFNULL(PO.BTRPCHR, 0) * ( CASE WHEN PO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) * (BA.ADCOPER)) AS BTRPECC_CAL , SUM(COALESCE( CASE WHEN TI.REGIORG != TI.REGIMOD AND PO.BTRPCHR < BO.BTRPCHR THEN ( BO.BTRPCHR * (CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END )) - (PO.BTRPCHR * (CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END) ) END, 0 )) AS SURCHCO_CAL , SUM( CASE WHEN TH.DOCTYPE = '810' AND (WEEKDAY(TI.POSHPDT) IN (5,6) OR ( TIME(TI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(MW.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(TI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(MW.HOLTMTO, '%H%i%s'), '%H%i%s') )) THEN BO.BTRPCHR * ( CASE WHEN BO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) * (MW.HOLRATE / 100) ELSE 0 END ) AS HOLICHR , SUM( CASE WHEN TH.DOCTYPE = '810' AND (WEEKDAY(TI.POSHPDT) IN (5,6) OR ( TIME(TI.POSHPTM) >= DATE_FORMAT(STR_TO_DATE(MW.HOLTMFM, '%H%i%s'), '%H%i%s') OR TIME(TI.POSHPTM) < DATE_FORMAT(STR_TO_DATE(MW.HOLTMTO, '%H%i%s'), '%H%i%s') )) THEN ( CASE WHEN PO.SIZGBYN = 'Y' THEN COALESCE(( SELECT BSIZPAY FROM ${userInfo.schema}.BSIZPA WHERE WAREKEY = #{param.warekey} AND BTRNKEY = PO.BTRPKEY AND ADDSIKY = BA.ADDSIKY ), 0) ELSE PO.BTRPPAY END ) * ( CASE WHEN PO.STNWEIG = #{param.stnweig} THEN COALESCE(TI.GROSSWG, 0) ELSE COALESCE(TI.SKUWEIG, 0) END ) * (MW.HOLRATE / 100) ELSE 0 END ) AS HOLIPAY FROM ${userInfo.schema}.TPLNIT TI INNER JOIN ${userInfo.schema}.TPLNHD TH ON TH.WAREKEY = TI.WAREKEY AND TH.VHPLNKY = TI.VHPLNKY INNER JOIN ${userInfo.schema}.MWARMA MW ON MW.WAREKEY = TI.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userInfo.schema}.BTRCAT BC ON BC.BTRCATE = TI.BTRCATE AND BC.PFONLYN = 'N' INNER JOIN ${userInfo.schema}.BADDCO BA ON BA.ADDCOKY = TI.ADDCOKY INNER JOIN ${userInfo.schema}.MDOCMA MD ON MD.WAREKEY = TH.WAREKEY AND MD.DOCCATE = TH.DOCCATE AND MD.DOCTYPE = TH.DOCTYPE INNER JOIN ${userInfo.commonSchema}.MVOWMA VO ON VO.VOWNKEY = TH.VOWNKEY AND VOUSEYN = 'Y'
LEFT JOIN ( SELECT WAREKEY, BTRCATE, BTRPKEY, REGIKEY , BTRPITC, BTRPITM, BTRPITN, BTRPIGB , BTRPICT, STNWEIG, BTRPVAF, BTRPCHR , BTRPPAY, BTRPEYN, BTRDFYN, BTRPDAF , BTRPDAT, SIZGBYN FROM ${userInfo.schema}.BTRPMA BP WHERE WAREKEY = #{param.warekey} ) BO ON BO.WAREKEY = TI.WAREKEY AND BO.BTRCATE = TI.BTRCATE AND BO.BTRPVAF = VO.VOWAFFI AND BO.REGIKEY = TI.REGIORG AND BO.BTRPITC = TI.ITEMCOD AND (DATE_FORMAT(TI.POSHPDT,'%Y%m') BETWEEN BO.BTRPDAF AND BO.BTRPDAT)
LEFT JOIN ( SELECT WAREKEY, BTRCATE, BTRPKEY, REGIKEY , BTRPITC, STNWEIG, BTRPVAF, BTRPCHR , BTRPPAY, BTRPEYN, SIZGBYN, BTRDFYN , BTRPDAF, BTRPDAT FROM ${userInfo.schema}.BTRPMA BP WHERE WAREKEY = #{param.warekey} ) PO ON PO.WAREKEY = TI.WAREKEY AND PO.BTRCATE = TI.BTRCATE AND PO.BTRPVAF = VO.VOWAFFI AND PO.REGIKEY = TI.REGIMOD AND PO.BTRPITC = TI.ITEMCOD AND (DATE_FORMAT(IFNULL(TI.TRNCPDT,TI.BILDATE),'%Y%m') BETWEEN PO.BTRPDAF AND PO.BTRPDAT)
AND TI.WAREKEY = #{param.warekey}
AND TI.BILDATE >= #{param.poshpdtfrom}
AND TI.BILDATE <= #{param.poshpdtto}
AND TI.BILDATE BETWEEN #{param.poshpdtfrom} AND #{param.poshpdtto}
AND TH.TPNSTAT IN ('FINISH','INVCMP') AND TI.TPISTAT IN ('ARRIVE','INVCMP')
GROUP BY BC.BTRCNAM, TH.DOCCATE, TH.DOCTYPE, TI.ITEMCOD , MD.DOCCTNM, MD.DOCTYNM, BTRPPAY, PO.BTRPCHR ) SELECT WR.BTRCNAM, WR.DOCCATE, WR.DOCTYPE, WR.DOCCTNM , WR.DOCTYNM, WR.ITEMCOD, WR.DAYWEIG , FLOOR((WR.BTRFCC1_CAL + WR.BTRFCC2_CAL + WR.BTRFCC3_CAL + WR.BTRFCC4_CAL)/1000) AS DAYTOCH , FLOOR(WR.BTRFEC1_CAL/1000) AS DAYEXCO , FLOOR((WR.BTRFCC1_CAL + WR.BTRFCC2_CAL + WR.BTRFCC3_CAL + WR.BTRFCC4_CAL + WR.BTRFEC1_CAL)/1000) AS TOTCHCO , FLOOR((WR.BTRFPC1_CAL + WR.BTRFPC2_CAL + WR.BTRFPC3_CAL + WR.BTRFPC4_CAL)/1000) AS DAYTOPA , FLOOR(WR.BTRFEP1_CAL/1000) AS DAYEXPA , FLOOR((WR.BTRFPC1_CAL + WR.BTRFPC2_CAL + WR.BTRFPC3_CAL + WR.BTRFPC4_CAL + WR.BTRFEP1_CAL)/1000) AS TOTPACO , FLOOR(WR.HOLICHR/1000) AS DAYHOCH , FLOOR(WR.HOLIPAY/1000) AS DAYHOPA FROM WRCVTIT_LIST WR UNION ALL SELECT TP.BTRCNAM, TP.DOCCATE, TP.DOCTYPE , TP.DOCCTNM , TP.DOCTYNM, TP.ITEMCOD, TP.DAYWEIG , FLOOR(TP.BTRPCCO_CAL/1000) AS DAYTOCH , FLOOR(TP.BTRPECC_CAL/1000) AS DAYEXCO , FLOOR((TP.BTRPCCO_CAL + TP.BTRPECC_CAL)/1000) AS TOTCHCO , FLOOR(TP.BTRPPCO_CAL/1000) AS DAYTOPA , FLOOR(TP.BTRPEPC_CAL/1000) AS DAYEXPA , FLOOR((TP.BTRPPCO_CAL + TP.BTRPPCO_CAL)/1000) AS TOTPACO , FLOOR(TP.HOLICHR/1000) AS DAYHOCH , FLOOR(TP.HOLIPAY/1000) AS DAYHOPA FROM TPLNIT_LIST TP
